  ('optometrist-moex-01170', 'optometrist', 'optometrist-moex-110-ddcf1380', 'sub-optometrist-04', NULL, 'single_choice', '一副透光率為25%的黑色鏡片，其鏡片厚度為2 mm，在不考慮表面反射條件下，則鏡片的每1 mm厚度 透光率為何？', '["6%", "50%", "63%", "75%"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:46+00:00", "source_pdf_sha1": "0b4912735e4c", "answer_pdf_sha1": "c510c33b9b6c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視覺光學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
